import React, { useState, useEffect } from 'react';
import { useParams, useNavigate, useLocation } from 'react-router-dom';
import { 
  FaDownload, FaEye, FaBook, FaFilePdf, FaFileAlt, 
  FaQuestionCircle, FaHistory, FaArrowLeft, FaBookOpen, 
  FaClock, FaStar, FaPrint, FaSpinner, FaFileWord, 
  FaFilePowerpoint, FaFileImage, FaFileArchive, FaFilter,
  FaUser, FaCalendar, FaFile, FaSort, FaSortUp, FaSortDown,
  FaSearch
} from 'react-icons/fa';
import { 
  getMaterialsForSubject, 
  downloadMaterial,
  getSubjectsForSemester 
} from '../services/api';

const MaterialsPage = () => {
  const { courseId, yearId, semId, subjectId } = useParams();
  const navigate = useNavigate();
  const location = useLocation();
  
  const [subject, setSubject] = useState(null);
  const [materials, setMaterials] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedType, setSelectedType] = useState('all');
  const [downloading, setDownloading] = useState({});
  const [searchQuery, setSearchQuery] = useState('');
  const [sortBy, setSortBy] = useState('date');
  const [sortOrder, setSortOrder] = useState('desc');

  // Styles Object - Pure Inline CSS
  const styles = {
    // Main Container
    container: {
      minHeight: '100vh',
      background: 'linear-gradient(135deg, #f5f7fa 0%, #c3cfe2 100%)',
      padding: '20px',
      fontFamily: '"Segoe UI", Tahoma, Geneva, Verdana, sans-serif'
    },
    
    // Inner Container
    innerContainer: {
      maxWidth: '1200px',
      margin: '0 auto'
    },
    
    // Back Button
    backButton: {
      display: 'inline-flex',
      alignItems: 'center',
      gap: '8px',
      padding: '12px 24px',
      background: '#4f46e5',
      color: 'white',
      border: 'none',
      borderRadius: '8px',
      cursor: 'pointer',
      fontWeight: '600',
      fontSize: '16px',
      marginBottom: '30px',
      boxShadow: '0 4px 6px rgba(79, 70, 229, 0.2)',
      transition: 'all 0.3s ease'
    },
    backButtonHover: {
      background: '#4338ca',
      transform: 'translateX(-5px)'
    },
    
    // Subject Header
    subjectHeader: {
      background: 'white',
      padding: '30px',
      borderRadius: '16px',
      marginBottom: '30px',
      boxShadow: '0 10px 25px rgba(0, 0, 0, 0.1)',
      display: 'flex',
      alignItems: 'center',
      gap: '25px'
    },
    subjectIconContainer: {
      width: '90px',
      height: '90px',
      borderRadius: '50%',
      background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      flexShrink: '0'
    },
    subjectIcon: {
      fontSize: '40px',
      color: 'white'
    },
    subjectInfo: {
      flex: '1'
    },
    subjectName: {
      fontSize: '32px',
      fontWeight: '700',
      color: '#1f2937',
      marginBottom: '10px'
    },
    subjectCode: {
      fontSize: '18px',
      color: '#6b7280',
      marginBottom: '15px',
      display: 'flex',
      alignItems: 'center',
      gap: '20px'
    },
    breadcrumb: {
      display: 'flex',
      alignItems: 'center',
      gap: '10px',
      fontSize: '14px',
      color: '#9ca3af'
    },
    breadcrumbItem: {
      padding: '6px 12px',
      background: '#f3f4f6',
      borderRadius: '6px'
    },
    currentBreadcrumb: {
      background: '#4f46e5',
      color: 'white'
    },
    statsBox: {
      background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
      padding: '20px',
      borderRadius: '12px',
      color: 'white',
      textAlign: 'center',
      minWidth: '120px'
    },
    statsNumber: {
      fontSize: '32px',
      fontWeight: '700',
      marginBottom: '5px'
    },
    statsLabel: {
      fontSize: '14px',
      opacity: '0.9'
    },
    
    // Search Bar
    searchContainer: {
      background: 'white',
      padding: '20px',
      borderRadius: '12px',
      marginBottom: '25px',
      boxShadow: '0 4px 6px rgba(0, 0, 0, 0.05)'
    },
    searchWrapper: {
      position: 'relative'
    },
    searchInput: {
      width: '100%',
      padding: '16px 20px 16px 50px',
      fontSize: '16px',
      border: '2px solid #e5e7eb',
      borderRadius: '10px',
      background: '#f9fafb',
      transition: 'all 0.3s'
    },
    searchInputFocus: {
      borderColor: '#4f46e5',
      boxShadow: '0 0 0 3px rgba(79, 70, 229, 0.1)',
      background: 'white'
    },
    searchIcon: {
      position: 'absolute',
      left: '20px',
      top: '50%',
      transform: 'translateY(-50%)',
      color: '#9ca3af',
      fontSize: '18px'
    },
    clearButton: {
      position: 'absolute',
      right: '20px',
      top: '50%',
      transform: 'translateY(-50%)',
      background: 'none',
      border: 'none',
      color: '#9ca3af',
      cursor: 'pointer',
      fontSize: '18px'
    },
    
    // Sort Controls
    sortContainer: {
      display: 'flex',
      alignItems: 'center',
      gap: '15px',
      marginTop: '15px'
    },
    sortLabel: {
      color: '#6b7280',
      fontWeight: '600'
    },
    sortButtons: {
      display: 'flex',
      gap: '10px'
    },
    sortButton: {
      padding: '8px 16px',
      background: '#f3f4f6',
      border: 'none',
      borderRadius: '6px',
      cursor: 'pointer',
      fontWeight: '500',
      color: '#4b5563',
      fontSize: '14px',
      display: 'flex',
      alignItems: 'center',
      gap: '6px',
      transition: 'all 0.2s'
    },
    sortButtonActive: {
      background: '#4f46e5',
      color: 'white'
    },
    
    // Filter Section
    filterSection: {
      background: 'white',
      padding: '25px',
      borderRadius: '12px',
      marginBottom: '30px',
      boxShadow: '0 4px 6px rgba(0, 0, 0, 0.05)'
    },
    filterTitle: {
      fontSize: '20px',
      fontWeight: '600',
      color: '#1f2937',
      marginBottom: '20px'
    },
    filterButtons: {
      display: 'flex',
      flexWrap: 'wrap',
      gap: '12px'
    },
    filterButton: {
      padding: '12px 20px',
      border: '2px solid #e5e7eb',
      borderRadius: '10px',
      cursor: 'pointer',
      display: 'flex',
      alignItems: 'center',
      gap: '10px',
      fontSize: '15px',
      fontWeight: '500',
      transition: 'all 0.3s',
      minWidth: '140px'
    },
    filterButtonActive: {
      transform: 'translateY(-3px)',
      boxShadow: '0 6px 12px rgba(0, 0, 0, 0.1)'
    },
    
    // Materials Container
    materialsContainer: {
      background: 'white',
      borderRadius: '12px',
      marginBottom: '30px',
      boxShadow: '0 4px 6px rgba(0, 0, 0, 0.05)',
      overflow: 'hidden'
    },
    materialsHeader: {
      padding: '25px',
      borderBottom: '1px solid #e5e7eb'
    },
    materialsTitle: {
      fontSize: '24px',
      fontWeight: '700',
      color: '#1f2937',
      marginBottom: '5px'
    },
    materialsSubtitle: {
      color: '#6b7280',
      fontSize: '16px'
    },
    
    // Materials Grid
    materialsGrid: {
      padding: '25px',
      display: 'grid',
      gridTemplateColumns: '1fr',
      gap: '25px'
    },
    gridTwoCols: {
      gridTemplateColumns: 'repeat(2, 1fr)'
    },
    gridThreeCols: {
      gridTemplateColumns: 'repeat(3, 1fr)'
    },
    
    // Material Card
    materialCard: {
      border: '1px solid #e5e7eb',
      borderRadius: '12px',
      overflow: 'hidden',
      transition: 'all 0.4s ease',
      background: 'white'
    },
    materialCardHover: {
      transform: 'translateY(-8px)',
      boxShadow: '0 20px 40px rgba(0, 0, 0, 0.1)'
    },
    materialHeader: {
      padding: '18px',
      display: 'flex',
      justifyContent: 'space-between',
      alignItems: 'center',
      borderBottom: '1px solid #e5e7eb'
    },
    typeBadge: {
      display: 'flex',
      alignItems: 'center',
      gap: '8px',
      padding: '8px 16px',
      borderRadius: '8px',
      fontSize: '14px',
      fontWeight: '600'
    },
    newBadge: {
      background: '#ef4444',
      color: 'white',
      padding: '4px 12px',
      borderRadius: '20px',
      fontSize: '12px',
      fontWeight: '700'
    },
    materialContent: {
      padding: '25px'
    },
    materialTitle: {
      fontSize: '20px',
      fontWeight: '600',
      color: '#1f2937',
      marginBottom: '12px',
      lineHeight: '1.4'
    },
    materialDescription: {
      color: '#6b7280',
      fontSize: '15px',
      lineHeight: '1.6',
      marginBottom: '20px'
    },
    statsGrid: {
      display: 'grid',
      gridTemplateColumns: '1fr 1fr',
      gap: '15px',
      marginBottom: '20px'
    },
    statItem: {
      display: 'flex',
      alignItems: 'center',
      gap: '8px',
      color: '#6b7280',
      fontSize: '14px'
    },
    fileInfo: {
      display: 'flex',
      justifyContent: 'space-between',
      paddingTop: '15px',
      borderTop: '1px solid #e5e7eb',
      fontSize: '13px',
      color: '#9ca3af'
    },
    actionButtons: {
      display: 'flex',
      padding: '20px',
      background: '#f9fafb',
      borderTop: '1px solid #e5e7eb',
      gap: '12px'
    },
    previewButton: {
      flex: '1',
      padding: '14px',
      background: 'white',
      border: '2px solid #e5e7eb',
      borderRadius: '8px',
      cursor: 'pointer',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      gap: '10px',
      fontWeight: '600',
      color: '#4b5563',
      transition: 'all 0.3s'
    },
    previewButtonHover: {
      background: '#f3f4f6'
    },
    downloadButton: {
      flex: '2',
      padding: '14px',
      background: 'linear-gradient(135deg, #10b981 0%, #34d399 100%)',
      color: 'white',
      border: 'none',
      borderRadius: '8px',
      cursor: 'pointer',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      gap: '10px',
      fontWeight: '600',
      fontSize: '16px',
      transition: 'all 0.3s'
    },
    downloadButtonHover: {
      background: 'linear-gradient(135deg, #059669 0%, #10b981 100%)',
      boxShadow: '0 4px 12px rgba(16, 185, 129, 0.3)'
    },
    downloadButtonDisabled: {
      opacity: '0.7',
      cursor: 'not-allowed'
    },
    
    // Empty State
    emptyState: {
      textAlign: 'center',
      padding: '60px 20px'
    },
    emptyIcon: {
      fontSize: '60px',
      marginBottom: '20px',
      opacity: '0.5'
    },
    emptyTitle: {
      fontSize: '24px',
      fontWeight: '600',
      color: '#6b7280',
      marginBottom: '10px'
    },
    emptyText: {
      color: '#9ca3af',
      fontSize: '16px',
      marginBottom: '30px',
      maxWidth: '500px',
      margin: '0 auto 30px'
    },
    clearSearchButton: {
      padding: '12px 30px',
      background: '#4f46e5',
      color: 'white',
      border: 'none',
      borderRadius: '8px',
      cursor: 'pointer',
      fontWeight: '600',
      fontSize: '16px'
    },
    
    // Statistics Section
    statsSection: {
      background: 'white',
      padding: '30px',
      borderRadius: '12px',
      marginBottom: '30px',
      boxShadow: '0 4px 6px rgba(0, 0, 0, 0.05)'
    },
    statsTitle: {
      fontSize: '24px',
      fontWeight: '600',
      color: '#1f2937',
      marginBottom: '25px',
      display: 'flex',
      alignItems: 'center',
      gap: '10px'
    },
    statsGridMain: {
      display: 'grid',
      gridTemplateColumns: 'repeat(2, 1fr)',
      gap: '20px',
      marginBottom: '30px'
    },
    statsGridFourCols: {
      gridTemplateColumns: 'repeat(4, 1fr)'
    },
    statCard: {
      textAlign: 'center',
      padding: '25px',
      border: '1px solid #e5e7eb',
      borderRadius: '12px',
      transition: 'all 0.3s'
    },
    statCardHover: {
      borderColor: '#4f46e5',
      boxShadow: '0 4px 12px rgba(79, 70, 229, 0.1)'
    },
    statNumber: {
      fontSize: '36px',
      fontWeight: '700',
      marginBottom: '8px'
    },
    statName: {
      fontSize: '16px',
      color: '#6b7280',
      fontWeight: '600',
      marginBottom: '5px'
    },
    statDesc: {
      fontSize: '13px',
      color: '#9ca3af'
    },
    
    // Help Section
    helpSection: {
      background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
      padding: '30px',
      borderRadius: '12px',
      color: 'white'
    },
    helpContent: {
      display: 'flex',
      flexDirection: 'column',
      gap: '20px'
    },
    helpTitle: {
      fontSize: '22px',
      fontWeight: '600',
      marginBottom: '10px'
    },
    helpText: {
      fontSize: '16px',
      opacity: '0.9',
      lineHeight: '1.6'
    },
    helpButtons: {
      display: 'flex',
      gap: '15px',
      marginTop: '10px'
    },
    secondaryButton: {
      padding: '12px 24px',
      background: 'white',
      color: '#4f46e5',
      border: 'none',
      borderRadius: '8px',
      cursor: 'pointer',
      fontWeight: '600',
      fontSize: '16px',
      transition: 'all 0.3s'
    },
    secondaryButtonHover: {
      background: '#f3f4f6'
    },
    primaryButton: {
      padding: '12px 24px',
      background: 'rgba(255, 255, 255, 0.2)',
      color: 'white',
      border: '2px solid white',
      borderRadius: '8px',
      cursor: 'pointer',
      fontWeight: '600',
      fontSize: '16px',
      transition: 'all 0.3s'
    },
    primaryButtonHover: {
      background: 'rgba(255, 255, 255, 0.3)'
    },
    
    // Loading State
    loadingContainer: {
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'center',
      justifyContent: 'center',
      minHeight: '100vh',
      background: 'linear-gradient(135deg, #f5f7fa 0%, #c3cfe2 100%)'
    },
    loadingSpinner: {
      width: '60px',
      height: '60px',
      border: '5px solid #e5e7eb',
      borderTop: '5px solid #4f46e5',
      borderRadius: '50%',
      animation: 'spin 1s linear infinite',
      marginBottom: '20px'
    },
    loadingText: {
      fontSize: '18px',
      color: '#6b7280',
      fontWeight: '600',
      marginBottom: '10px'
    },
    loadingSubtext: {
      color: '#9ca3af',
      fontSize: '14px'
    },
    
    // Keyframes for animation
    keyframes: `
      @keyframes spin {
        0% { transform: rotate(0deg); }
        100% { transform: rotate(360deg); }
      }
    `
  };

  // Material types with colors
  const materialTypes = [
    { id: 'all', name: 'All Materials', icon: '📁', color: '#6b7280' },
    { id: 'syllabus', name: 'Syllabus', icon: '📚', color: '#3B82F6' },
    { id: 'notes', name: 'Notes', icon: '📝', color: '#10B981' },
    { id: 'pyq', name: 'PYQs', icon: '📖', color: '#8B5CF6' },
    { id: 'important', name: 'Imp Questions', icon: '❓', color: '#F59E0B' },
    { id: 'lab', name: 'Lab Manuals', icon: '🔬', color: '#EF4444' },
    { id: 'assignment', name: 'Assignments', icon: '📄', color: '#EC4899' }
  ];

  // Color mapping for material types
  const typeColors = {
    syllabus: '#3B82F6',
    notes: '#10B981',
    pyq: '#8B5CF6',
    important: '#F59E0B',
    lab: '#EF4444',
    assignment: '#EC4899'
  };

  // Format date
  const formatDate = (dateString) => {
    if (!dateString) return 'Recent';
    return dateString;
  };

  // Format file size
  const formatFileSize = (size) => {
    if (!size) return '1-2 MB';
    return size;
  };

  // Fetch data
  useEffect(() => {
    const fetchData = async () => {
      try {
        setLoading(true);
        
        // Mock data for now
        const mockSubject = {
          name: 'Mathematics-I',
          code: 'MATH101',
          credits: 4,
          description: 'Fundamental mathematics course covering algebra, calculus and trigonometry.'
        };
        
        const mockMaterials = [
          {
            id: 1,
            title: 'Complete Syllabus 2024',
            type: 'syllabus',
            description: 'Official syllabus with unit-wise distribution and marking scheme',
            fileSize: '1.2 MB',
            pages: 12,
            uploadDate: '15 Jan 2024',
            downloads: 245,
            views: 510,
            rating: 4.5,
            user: 'Admin',
            isNew: true
          },
          {
            id: 2,
            title: 'Complete Notes - Unit 1 to 5',
            type: 'notes',
            description: 'Handwritten notes with diagrams, examples and solved problems',
            fileSize: '4.5 MB',
            pages: 45,
            uploadDate: '20 Jan 2024',
            downloads: 420,
            views: 880,
            rating: 4.8,
            user: 'Prof. Sharma',
            isNew: true
          },
          {
            id: 3,
            title: 'PYQ 2020-2023',
            type: 'pyq',
            description: 'Previous year questions with detailed solutions and explanations',
            fileSize: '3.2 MB',
            pages: 35,
            uploadDate: '05 Jan 2024',
            downloads: 520,
            views: 1200,
            rating: 4.9,
            user: 'Admin'
          },
          {
            id: 4,
            title: 'Important Questions Set 1',
            type: 'important',
            description: 'Most expected questions for semester exams with answers',
            fileSize: '1.5 MB',
            pages: 18,
            uploadDate: '22 Jan 2024',
            downloads: 380,
            views: 650,
            rating: 4.4,
            user: 'Exam Cell'
          }
        ];
        
        setTimeout(() => {
          setSubject(mockSubject);
          setMaterials(mockMaterials);
          setLoading(false);
        }, 1000);
        
      } catch (error) {
        console.error('Error:', error);
        setLoading(false);
      }
    };
    
    fetchData();
  }, []);

  // Handle back
  const handleBack = () => {
    navigate(-1);
  };

  // Handle download
  const handleDownload = (material) => {
    setDownloading(prev => ({ ...prev, [material.id]: true }));
    
    setTimeout(() => {
      alert(`✅ Downloaded: ${material.title}\n\nFile will be saved as "${material.title}.pdf"`);
      setDownloading(prev => ({ ...prev, [material.id]: false }));
      
      // Update download count
      setMaterials(prev => 
        prev.map(m => 
          m.id === material.id 
            ? { ...m, downloads: m.downloads + 1 } 
            : m
        )
      );
    }, 1500);
  };

  // Handle preview
  const handlePreview = (material) => {
    alert(`📄 Preview: ${material.title}\n\n${material.description}\n\n📊 Stats:\n• Downloads: ${material.downloads}\n• Views: ${material.views}\n• Rating: ${material.rating}/5\n\nNote: In production, PDF preview will open.`);
  };

  // Handle sort
  const handleSort = (field) => {
    if (sortBy === field) {
      setSortOrder(sortOrder === 'asc' ? 'desc' : 'asc');
    } else {
      setSortBy(field);
      setSortOrder('desc');
    }
  };

  // Filter and sort materials
  const filteredMaterials = materials
    .filter(material => {
      const matchesType = selectedType === 'all' || material.type === selectedType;
      const matchesSearch = searchQuery === '' || 
        material.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
        material.description.toLowerCase().includes(searchQuery.toLowerCase());
      return matchesType && matchesSearch;
    })
    .sort((a, b) => {
      let aVal, bVal;
      
      switch (sortBy) {
        case 'date':
          aVal = new Date(a.uploadDate);
          bVal = new Date(b.uploadDate);
          break;
        case 'downloads':
          aVal = a.downloads;
          bVal = b.downloads;
          break;
        case 'rating':
          aVal = a.rating;
          bVal = b.rating;
          break;
        case 'name':
          aVal = a.title.toLowerCase();
          bVal = b.title.toLowerCase();
          break;
        default:
          return 0;
      }
      
      return sortOrder === 'asc' 
        ? (aVal > bVal ? 1 : -1)
        : (aVal < bVal ? 1 : -1);
    });

  // Calculate stats
  const calculateStats = () => {
    const stats = {};
    materialTypes.forEach(type => {
      if (type.id !== 'all') {
        stats[type.id] = materials.filter(m => m.type === type.id).length;
      }
    });
    return stats;
  };

  const materialStats = calculateStats();
  const [isHovered, setIsHovered] = useState({});

  if (loading) {
    return (
      <div style={styles.loadingContainer}>
        <style>{styles.keyframes}</style>
        <div style={styles.loadingSpinner}></div>
        <div style={styles.loadingText}>Loading Study Materials...</div>
        <div style={styles.loadingSubtext}>Preparing the best resources for you</div>
      </div>
    );
  }

  return (
    <div style={styles.container}>
      <style>{styles.keyframes}</style>
      <div style={styles.innerContainer}>
        
        {/* Back Button */}
        <button 
          style={styles.backButton}
          onMouseEnter={(e) => {
            e.currentTarget.style.background = styles.backButtonHover.background;
            e.currentTarget.style.transform = styles.backButtonHover.transform;
          }}
          onMouseLeave={(e) => {
            e.currentTarget.style.background = styles.backButton.background;
            e.currentTarget.style.transform = 'none';
          }}
          onClick={handleBack}
        >
          <FaArrowLeft /> Back to Subjects
        </button>

        {/* Subject Header */}
        <div style={styles.subjectHeader}>
          <div style={styles.subjectIconContainer}>
            <div style={styles.subjectIcon}>📚</div>
          </div>
          
          <div style={styles.subjectInfo}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
              <div>
                <h1 style={styles.subjectName}>{subject?.name}</h1>
                <div style={styles.subjectCode}>
                  <span>Code: <strong>{subject?.code}</strong></span>
                  <span>⭐ <strong>{subject?.credits} Credits</strong></span>
                  <span>📁 <strong>{materials.length} Materials</strong></span>
                </div>
                
                <div style={styles.breadcrumb}>
                  <span style={styles.breadcrumbItem}>Course {courseId || 2}</span>
                  <span>→</span>
                  <span style={styles.breadcrumbItem}>Year {yearId || 1}</span>
                  <span>→</span>
                  <span style={styles.breadcrumbItem}>Semester {semId || 1}</span>
                  <span>→</span>
                  <span style={{ ...styles.breadcrumbItem, ...styles.currentBreadcrumb }}>
                    {subject?.name}
                  </span>
                </div>
                
                {subject?.description && (
                  <div style={{ 
                    marginTop: '20px', 
                    padding: '15px', 
                    background: '#f0f9ff', 
                    borderRadius: '8px',
                    borderLeft: '4px solid #3B82F6'
                  }}>
                    <p style={{ margin: 0, color: '#0369a1' }}>{subject.description}</p>
                  </div>
                )}
              </div>
              
              <div style={styles.statsBox}>
                <div style={styles.statsNumber}>{materials.length}</div>
                <div style={styles.statsLabel}>Total Files</div>
                <div style={{ ...styles.statsLabel, fontSize: '12px', marginTop: '5px' }}>Ready to Download</div>
              </div>
            </div>
          </div>
        </div>

        {/* Search Bar */}
        <div style={styles.searchContainer}>
          <div style={styles.searchWrapper}>
            <input
              type="text"
              placeholder="Search notes, pyqs, syllabus..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              style={{
                ...styles.searchInput,
                ...(searchQuery ? styles.searchInputFocus : {})
              }}
              onFocus={(e) => {
                e.target.style.borderColor = styles.searchInputFocus.borderColor;
                e.target.style.boxShadow = styles.searchInputFocus.boxShadow;
                e.target.style.background = styles.searchInputFocus.background;
              }}
              onBlur={(e) => {
                if (!searchQuery) {
                  e.target.style.borderColor = styles.searchInput.borderColor;
                  e.target.style.boxShadow = 'none';
                  e.target.style.background = styles.searchInput.background;
                }
              }}
            />
            <div style={styles.searchIcon}>
              <FaSearch />
            </div>
            {searchQuery && (
              <button
                style={styles.clearButton}
                onClick={() => setSearchQuery('')}
              >
                ✕
              </button>
            )}
          </div>
          
          <div style={styles.sortContainer}>
            <div style={styles.sortLabel}>Sort by:</div>
            <div style={styles.sortButtons}>
              {['date', 'downloads', 'rating', 'name'].map((field) => (
                <button
                  key={field}
                  style={{
                    ...styles.sortButton,
                    ...(sortBy === field ? styles.sortButtonActive : {})
                  }}
                  onClick={() => handleSort(field)}
                >
                  {field.charAt(0).toUpperCase() + field.slice(1)}
                  {sortBy === field && (
                    sortOrder === 'asc' ? <FaSortUp /> : <FaSortDown />
                  )}
                </button>
              ))}
            </div>
          </div>
        </div>

        {/* Filter Section */}
        <div style={styles.filterSection}>
          <h3 style={styles.filterTitle}>Filter by Material Type</h3>
          <div style={styles.filterButtons}>
            {materialTypes.map((type) => (
              <button
                key={type.id}
                style={{
                  ...styles.filterButton,
                  borderColor: type.color,
                  background: selectedType === type.id ? `${type.color}15` : 'white',
                  color: selectedType === type.id ? type.color : '#4b5563',
                  ...(selectedType === type.id ? styles.filterButtonActive : {})
                }}
                onClick={() => setSelectedType(type.id)}
                onMouseEnter={(e) => {
                  if (selectedType !== type.id) {
                    e.currentTarget.style.transform = 'translateY(-2px)';
                    e.currentTarget.style.boxShadow = '0 4px 8px rgba(0,0,0,0.1)';
                  }
                }}
                onMouseLeave={(e) => {
                  if (selectedType !== type.id) {
                    e.currentTarget.style.transform = 'none';
                    e.currentTarget.style.boxShadow = 'none';
                  }
                }}
              >
                <span style={{ fontSize: '18px' }}>{type.icon}</span>
                {type.name}
                {type.id !== 'all' && (
                  <span style={{
                    marginLeft: '8px',
                    background: '#f3f4f6',
                    color: '#6b7280',
                    padding: '2px 8px',
                    borderRadius: '12px',
                    fontSize: '12px',
                    fontWeight: 'bold'
                  }}>
                    {materialStats[type.id] || 0}
                  </span>
                )}
              </button>
            ))}
          </div>
        </div>

        {/* Materials Grid */}
        <div style={styles.materialsContainer}>
          <div style={styles.materialsHeader}>
            <h2 style={styles.materialsTitle}>
              {selectedType === 'all' ? 'All Study Materials' : materialTypes.find(t => t.id === selectedType)?.name}
            </h2>
            <p style={styles.materialsSubtitle}>
              {filteredMaterials.length} material{filteredMaterials.length !== 1 ? 's' : ''} found
              {searchQuery && ` for "${searchQuery}"`}
            </p>
          </div>
          
          {filteredMaterials.length === 0 ? (
            <div style={styles.emptyState}>
              <div style={styles.emptyIcon}>📭</div>
              <h3 style={styles.emptyTitle}>
                {searchQuery ? 'No materials found' : 'No materials available'}
              </h3>
              <p style={styles.emptyText}>
                {searchQuery 
                  ? `We couldn't find any materials matching "${searchQuery}". Try different keywords.`
                  : 'Be the first to upload study materials for this subject!'
                }
              </p>
              {searchQuery && (
                <button
                  style={styles.clearSearchButton}
                  onClick={() => setSearchQuery('')}
                >
                  Clear Search
                </button>
              )}
            </div>
          ) : (
            <div style={{
              ...styles.materialsGrid,
              ...(filteredMaterials.length >= 2 ? styles.gridTwoCols : {}),
              ...(filteredMaterials.length >= 3 ? styles.gridThreeCols : {})
            }}>
              {filteredMaterials.map((material) => {
                const typeColor = typeColors[material.type] || '#6b7280';
                
                return (
                  <div
                    key={material.id}
                    style={{
                      ...styles.materialCard,
                      ...(isHovered[material.id] ? styles.materialCardHover : {})
                    }}
                    onMouseEnter={() => setIsHovered(prev => ({ ...prev, [material.id]: true }))}
                    onMouseLeave={() => setIsHovered(prev => ({ ...prev, [material.id]: false }))}
                  >
                    {/* Header */}
                    <div style={{
                      ...styles.materialHeader,
                      background: `${typeColor}10`,
                      borderColor: `${typeColor}30`
                    }}>
                      <div style={{
                        ...styles.typeBadge,
                        background: `${typeColor}15`,
                        color: typeColor,
                        borderLeft: `4px solid ${typeColor}`
                      }}>
                        <span>{materialTypes.find(t => t.id === material.type)?.icon || '📄'}</span>
                        <span>{materialTypes.find(t => t.id === material.type)?.name || 'Material'}</span>
                      </div>
                      
                      <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '5px', color: '#6b7280', fontSize: '14px' }}>
                          <FaUser size={12} /> {material.user}
                        </div>
                        {material.isNew && (
                          <span style={styles.newBadge}>NEW</span>
                        )}
                      </div>
                    </div>
                    
                    {/* Content */}
                    <div style={styles.materialContent}>
                      <h3 style={styles.materialTitle}>{material.title}</h3>
                      <p style={styles.materialDescription}>{material.description}</p>
                      
                      <div style={styles.statsGrid}>
                        <div style={styles.statItem}>
                          <FaClock color="#9ca3af" size={14} />
                          <span>{formatDate(material.uploadDate)}</span>
                        </div>
                        <div style={styles.statItem}>
                          <FaDownload color="#9ca3af" size={14} />
                          <span>{material.downloads} downloads</span>
                        </div>
                        <div style={styles.statItem}>
                          <FaEye color="#9ca3af" size={14} />
                          <span>{material.views} views</span>
                        </div>
                        <div style={styles.statItem}>
                          <FaStar color="#fbbf24" size={14} />
                          <span>{material.rating}/5 rating</span>
                        </div>
                      </div>
                      
                      <div style={styles.fileInfo}>
                        <span>📄 {formatFileSize(material.fileSize)}</span>
                        <span>📖 {material.pages} pages</span>
                      </div>
                    </div>
                    
                    {/* Action Buttons */}
                    <div style={styles.actionButtons}>
                      <button
                        style={styles.previewButton}
                        onClick={() => handlePreview(material)}
                        onMouseEnter={(e) => {
                          e.currentTarget.style.background = styles.previewButtonHover.background;
                        }}
                        onMouseLeave={(e) => {
                          e.currentTarget.style.background = styles.previewButton.background;
                        }}
                      >
                        <FaEye /> Preview
                      </button>
                      
                      <button
                        style={{
                          ...styles.downloadButton,
                          ...(downloading[material.id] ? styles.downloadButtonDisabled : {})
                        }}
                        onClick={() => handleDownload(material)}
                        disabled={downloading[material.id]}
                        onMouseEnter={(e) => {
                          if (!downloading[material.id]) {
                            e.currentTarget.style.background = styles.downloadButtonHover.background;
                            e.currentTarget.style.boxShadow = styles.downloadButtonHover.boxShadow;
                          }
                        }}
                        onMouseLeave={(e) => {
                          if (!downloading[material.id]) {
                            e.currentTarget.style.background = styles.downloadButton.background;
                            e.currentTarget.style.boxShadow = 'none';
                          }
                        }}
                      >
                        {downloading[material.id] ? (
                          <>
                            <FaSpinner style={{ animation: 'spin 1s linear infinite' }} />
                            Downloading...
                          </>
                        ) : (
                          <>
                            <FaDownload /> Download
                          </>
                        )}
                      </button>
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>

        {/* Statistics Section */}
        <div style={styles.statsSection}>
          <h3 style={styles.statsTitle}>
            <span style={{ fontSize: '28px' }}>📊</span> Material Statistics
          </h3>
          
          <div style={{
            ...styles.statsGridMain,
            ...styles.statsGridFourCols
          }}>
            {materialTypes.slice(1, 5).map((type) => (
              <div
                key={type.id}
                style={{
                  ...styles.statCard,
                  borderTop: `4px solid ${type.color}`
                }}
                onMouseEnter={(e) => {
                  e.currentTarget.style.borderColor = styles.statCardHover.borderColor;
                  e.currentTarget.style.boxShadow = styles.statCardHover.boxShadow;
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.borderColor = '#e5e7eb';
                  e.currentTarget.style.boxShadow = 'none';
                }}
              >
                <div style={{ ...styles.statNumber, color: type.color }}>
                  {materialStats[type.id] || 0}
                </div>
                <div style={styles.statName}>{type.name}</div>
                <div style={styles.statDesc}>
                  {type.id === 'syllabus' && 'Course outlines'}
                  {type.id === 'notes' && 'Study materials'}
                  {type.id === 'pyq' && 'Previous papers'}
                  {type.id === 'important' && 'Important Qs'}
                </div>
              </div>
            ))}
          </div>
          
          <div style={{
            paddingTop: '20px',
            borderTop: '1px solid #e5e7eb',
            display: 'flex',
            justifyContent: 'space-between',
            alignItems: 'center',
            flexWrap: 'wrap',
            gap: '15px'
          }}>
            <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
                <span style={{ color: '#6b7280', fontWeight: '600' }}>📥 Total Downloads:</span>
                <span style={{ color: '#059669', fontWeight: '700', fontSize: '18px' }}>
                  {materials.reduce((sum, m) => sum + m.downloads, 0).toLocaleString()}
                </span>
              </div>
              <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
                <span style={{ color: '#6b7280', fontWeight: '600' }}>👁️ Total Views:</span>
                <span style={{ color: '#3B82F6', fontWeight: '700', fontSize: '18px' }}>
                  {materials.reduce((sum, m) => sum + m.views, 0).toLocaleString()}
                </span>
              </div>
            </div>
            
            <div style={{ display: 'flex', gap: '12px' }}>
              <button
                style={styles.secondaryButton}
                onClick={() => window.print()}
                onMouseEnter={(e) => {
                  e.currentTarget.style.background = styles.secondaryButtonHover.background;
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.background = styles.secondaryButton.background;
                }}
              >
                <FaPrint style={{ marginRight: '8px' }} />
                Print Summary
              </button>
              
              <button
                style={styles.primaryButton}
                onClick={() => alert('Share feature coming soon!')}
                onMouseEnter={(e) => {
                  e.currentTarget.style.background = styles.primaryButtonHover.background;
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.background = styles.primaryButton.background;
                }}
              >
                Share This Page
              </button>
            </div>
          </div>
        </div>

        {/* Help Section */}
        <div style={styles.helpSection}>
          <div style={styles.helpContent}>
            <div>
              <h4 style={styles.helpTitle}>💡 Need Help with Studies?</h4>
              <p style={styles.helpText}>
                Join our student community for discussions, doubts, and study groups.
                Connect with peers studying the same subject!
              </p>
            </div>
            
            <div style={styles.helpButtons}>
              <button
                style={styles.secondaryButton}
                onClick={() => navigate('/community')}
                onMouseEnter={(e) => {
                  e.currentTarget.style.background = styles.secondaryButtonHover.background;
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.background = styles.secondaryButton.background;
                }}
              >
                Join Community
              </button>
              
              <button
                style={styles.primaryButton}
                onClick={() => navigate('/upload')}
                onMouseEnter={(e) => {
                  e.currentTarget.style.background = styles.primaryButtonHover.background;
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.background = styles.primaryButton.background;
                }}
              >
                Upload Notes
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default MaterialsPage;
